let wavesurfer;
function loadScript(src) {
  return new Promise((resolve, reject) => {
    const script = document.createElement("script");
    script.src = src;
    script.onload = resolve;
    script.onerror = reject;
    document.body.appendChild(script);
  });
}
async function init(audioUrl) {
  if (!audioUrl) return;
  console.log("init audioUrl:", audioUrl);

  // Load WaveSurfer (v7)
  if (!window.WaveSurfer) {
    await loadScript("https://unpkg.com/wavesurfer.js@7/dist/wavesurfer.min.js");
  }
  const player = document.getElementById("player");

  // set audio source
  player.src = audioUrl;
  player.load();

  // create WaveSurfer ONCE
  if (!wavesurfer) {
    wavesurfer = WaveSurfer.create({
      container: "#waveform",
      media: player,
      // KEY: syncs waveform + audio
      waveColor: "#A2B1BA",
      progressColor: "#4BC58F",
      height: 120
    });
    console.log("WaveSurfer created");
  }
}
appsmith.onReady(() => {
  init(appsmith.model.audioUrl);
  appsmith.onModelChange(model => {
    console.log("model changed:", model);
    init(model.audioUrl); // reload audio safely
  });
});

